// Erzeugt ein Passwort. Eingabe: { laenge?: number, sonderzeichen?: boolean }
// Hinweis: Demo nutzt Math.random (fuer echte Schluessel crypto verwenden).
async function run(input) {
  const laenge = Math.min(64, Math.max(8, Number((input && input.laenge) || 16)));
  const sonder = !input || input.sonderzeichen !== false;
  let pool = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  if (sonder) pool += '!@#$%^&*()-_=+[]{}';
  let pw = '';
  for (let i = 0; i < laenge; i++) pw += pool[Math.floor(Math.random() * pool.length)];
  return { passwort: pw, laenge };
}
